"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import { useTRPC } from "@repo/app-trpc/react";
import type { TeamSettingsFormValues } from "@repo/app-validation/forms";
import { teamSettingsFormSchema } from "@repo/app-validation/forms";
import { Button } from "@repo/ui/components/ui/button";
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
  useFormCompat,
} from "@repo/ui/components/ui/form";
import { Input } from "@repo/ui/components/ui/input";
import { toast } from "@repo/ui/components/ui/sonner";
import {
  useMutation,
  useQueryClient,
  useSuspenseQuery,
} from "@tanstack/react-query";
import { useOrganizationList } from "@vendor/clerk/client";
import { Loader2 } from "lucide-react";
import { useRouter } from "next/navigation";
import { useState } from "react";

interface TeamGeneralSettingsClientProps {
  slug: string;
}

export function TeamGeneralSettingsClient({
  slug,
}: TeamGeneralSettingsClientProps) {
  const router = useRouter();
  const trpc = useTRPC();
  const queryClient = useQueryClient();
  const { setActive } = useOrganizationList();
  const [isUpdating, setIsUpdating] = useState(false);

  // Use cached organization list from app layout (avoids Clerk 404 timing issues)
  const { data: organizations } = useSuspenseQuery(
    trpc.organization.listUserOrganizations.queryOptions(),
  );

  // Find current organization from cached list by slug
  const organization = organizations.find((org) => org.slug === slug);

  if (!organization) {
    throw new Error(`Organization not found: ${slug}`);
  }

  // Initialize form with current organization name
  const form = useFormCompat<TeamSettingsFormValues>({
    resolver: zodResolver(teamSettingsFormSchema),
    defaultValues: {
      teamName: organization.slug,
    },
    mode: "onChange",
  });

  // Watch for changes
  const currentFormName = form.watch("teamName");
  const hasChanges = currentFormName !== organization.slug;

  const orgListQueryKey =
    trpc.organization.listUserOrganizations.queryOptions().queryKey;

  // Update organization name mutation — optimistic cache update
  // so sidebar, header, and useActiveOrg all reflect the new name instantly
  const updateNameMutation = useMutation(
    trpc.organization.updateName.mutationOptions({
      meta: { errorTitle: "Failed to update team name" },

      onMutate: async (input) => {
        await queryClient.cancelQueries({ queryKey: orgListQueryKey });
        const previousOrgs = queryClient.getQueryData(orgListQueryKey);
        queryClient.setQueryData(orgListQueryKey, (old: typeof previousOrgs) =>
          old?.map((org) =>
            org.slug === input.slug ? { ...org, slug: input.name } : org,
          ),
        );
        return { previousOrgs };
      },

      onError: (_err, _input, context) => {
        if (context?.previousOrgs) {
          queryClient.setQueryData(orgListQueryKey, context.previousOrgs);
        }
      },

      onSuccess: async (data) => {
        toast.success("Team updated!", {
          description: `Team name changed to "${data.name}"`,
        });

        // Update Clerk's active organization before navigation
        // This ensures cookies are updated before the RSC request
        try {
          if (setActive) {
            await setActive({ organization: data.id });
          }

          // Refresh router cache to clear any stale RSC data
          router.refresh();

          // Navigate with updated cookies (client-side navigation)
          router.push(`/${data.name}/settings`);
        } catch (error) {
          console.error("Failed to set active organization:", error);
          // Still navigate, but may cause temporary mismatch
          router.push(`/${data.name}/settings`);
        }
      },

      onSettled: () => {
        // Invalidate to ensure consistency with server
        void queryClient.invalidateQueries({ queryKey: orgListQueryKey });
        setIsUpdating(false);
      },
    }),
  );

  const onSubmit = async (values: TeamSettingsFormValues) => {
    // Trigger validation
    const isValid = await form.trigger();
    if (!isValid) {
      toast.error("Validation failed", {
        description: "Please fix the errors in the form before submitting.",
      });
      return;
    }

    setIsUpdating(true);

    updateNameMutation.mutate({
      slug,
      name: values.teamName,
    });
  };

  return (
    <div className="space-y-8">
      <div>
        <h2 className="font-medium font-pp text-2xl text-foreground">
          General
        </h2>
        <p className="mt-1 text-muted-foreground text-sm">
          Manage your team's profile and preferences.
        </p>
      </div>
      <Form {...form}>
        <form className="space-y-8" onSubmit={form.handleSubmit(onSubmit)}>
          {/* Team Name Section */}
          <div className="space-y-4">
            <div>
              <h2 className="font-semibold text-foreground text-xl">
                Team Name
              </h2>
              <p className="mt-1 text-muted-foreground text-sm">
                This is your team's visible name within Lightfast.
              </p>
            </div>

            <div className="w-full space-y-4">
              <FormField
                control={form.control}
                name="teamName"
                render={({ field }) => (
                  <FormItem>
                    <FormControl>
                      <Input
                        {...field}
                        onChange={(e) => {
                          // Normalize: lowercase, alphanumeric + hyphens only
                          const normalized = e.target.value
                            .toLowerCase()
                            .replace(/[^a-z0-9-]/g, "")
                            .replace(/^-+|-+$/g, ""); // Remove leading/trailing hyphens

                          field.onChange(normalized);
                        }}
                        placeholder="acme-inc"
                        type="text"
                      />
                    </FormControl>
                    <FormDescription>
                      Lowercase letters, numbers, and hyphens (3-39 characters)
                    </FormDescription>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <div className="flex justify-end">
                <Button
                  disabled={
                    !(hasChanges && form.formState.isValid) || isUpdating
                  }
                  type="submit"
                  variant="secondary"
                >
                  {isUpdating ? (
                    <>
                      <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                      Saving...
                    </>
                  ) : (
                    "Save"
                  )}
                </Button>
              </div>
            </div>
          </div>
        </form>
      </Form>
      {/* Additional Settings */}
      <div className="space-y-4">
        <div>
          <h2 className="font-semibold text-foreground text-xl">
            Additional Settings
          </h2>
          <p className="mt-1 text-muted-foreground text-sm">
            More team configuration options coming soon.
          </p>
        </div>
      </div>
    </div>
  );
}

import { db } from "@db/app/client";
import { orgApiKeys } from "@db/app/schema";
import { generateOrgApiKey, hashApiKey } from "@repo/app-api-key";
import {
  createOrgApiKeySchema,
  deleteOrgApiKeySchema,
  revokeOrgApiKeySchema,
  rotateOrgApiKeySchema,
} from "@repo/app-validation/schemas";
import type { TRPCRouterRecord } from "@trpc/server";
import { TRPCError } from "@trpc/server";
import { log } from "@vendor/observability/log/next";
import { and, desc, eq } from "drizzle-orm";
import { orgScopedProcedure } from "../../trpc";

/**
 * Organization API Keys Router
 *
 * Manages org-scoped API keys for secure API access.
 * Each key authenticates the org and can access all resources within it.
 *
 * Security:
 * - Keys are hashed using SHA-256 before storage (never store plaintext)
 * - Full key is only returned once on creation (never again)
 * - Keys can be revoked (soft delete) or permanently deleted
 * - Key rotation atomically revokes old key and creates new one
 */
export const orgApiKeysRouter = {
  /**
   * List all API keys for the org
   * Returns keys with preview only (never full key)
   */
  list: orgScopedProcedure.query(async ({ ctx }) => {
    const keys = await db
      .select({
        publicId: orgApiKeys.publicId,
        name: orgApiKeys.name,
        keyPrefix: orgApiKeys.keyPrefix,
        keySuffix: orgApiKeys.keySuffix,
        isActive: orgApiKeys.isActive,
        expiresAt: orgApiKeys.expiresAt,
        lastUsedAt: orgApiKeys.lastUsedAt,
        createdAt: orgApiKeys.createdAt,
        createdByUserId: orgApiKeys.createdByUserId,
      })
      .from(orgApiKeys)
      .where(eq(orgApiKeys.clerkOrgId, ctx.auth.orgId))
      .orderBy(desc(orgApiKeys.createdAt));

    return keys.map((key) => ({
      id: key.publicId,
      name: key.name,
      keyPreview: `${key.keyPrefix}...${key.keySuffix}`,
      isActive: key.isActive,
      expiresAt: key.expiresAt,
      lastUsedAt: key.lastUsedAt,
      createdAt: key.createdAt,
      createdByUserId: key.createdByUserId,
    }));
  }),

  /**
   * Create a new organization API key
   * Returns the full key ONLY on creation (never again)
   */
  create: orgScopedProcedure
    .input(createOrgApiKeySchema)
    .mutation(async ({ ctx, input }) => {
      const { key, prefix, suffix } = generateOrgApiKey();
      const keyHash = hashApiKey(key);

      const [created] = await db
        .insert(orgApiKeys)
        .values({
          clerkOrgId: ctx.auth.orgId,
          createdByUserId: ctx.auth.userId,
          name: input.name,
          keyHash,
          keyPrefix: prefix,
          keySuffix: suffix,
          expiresAt: input.expiresAt?.toISOString(),
        })
        .returning({
          id: orgApiKeys.id,
          publicId: orgApiKeys.publicId,
        });

      if (!created) {
        log.error("[org-api-keys] create failed", {
          clerkOrgId: ctx.auth.orgId,
          name: input.name,
        });
        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Failed to create API key",
        });
      }

      log.info("[org-api-keys] created", {
        clerkOrgId: ctx.auth.orgId,
        keyId: created.publicId,
        name: input.name,
      });

      return {
        id: created.publicId,
        key, // Full key - only returned once!
        name: input.name,
        keyPreview: `${prefix}...${suffix}`,
        expiresAt: input.expiresAt?.toISOString() ?? null,
        createdAt: new Date().toISOString(),
      };
    }),

  /**
   * Revoke (soft delete) an API key
   * Key remains in database but becomes inactive
   */
  revoke: orgScopedProcedure
    .input(revokeOrgApiKeySchema)
    .mutation(async ({ ctx, input }) => {
      const [existingKey] = await db
        .select({
          id: orgApiKeys.id,
          isActive: orgApiKeys.isActive,
        })
        .from(orgApiKeys)
        .where(
          and(
            eq(orgApiKeys.publicId, input.keyId),
            eq(orgApiKeys.clerkOrgId, ctx.auth.orgId)
          )
        )
        .limit(1);

      if (!existingKey) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "API key not found",
        });
      }

      if (!existingKey.isActive) {
        throw new TRPCError({
          code: "BAD_REQUEST",
          message: "API key is already revoked",
        });
      }

      await db
        .update(orgApiKeys)
        .set({ isActive: false, updatedAt: new Date().toISOString() })
        .where(eq(orgApiKeys.id, existingKey.id));

      log.info("[org-api-keys] revoked", {
        clerkOrgId: ctx.auth.orgId,
        keyId: input.keyId,
      });

      return { success: true };
    }),

  /**
   * Permanently delete an API key
   * Key is removed from database entirely
   */
  delete: orgScopedProcedure
    .input(deleteOrgApiKeySchema)
    .mutation(async ({ ctx, input }) => {
      const [existingKey] = await db
        .select({ id: orgApiKeys.id })
        .from(orgApiKeys)
        .where(
          and(
            eq(orgApiKeys.publicId, input.keyId),
            eq(orgApiKeys.clerkOrgId, ctx.auth.orgId)
          )
        )
        .limit(1);

      if (!existingKey) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "API key not found",
        });
      }

      await db.delete(orgApiKeys).where(eq(orgApiKeys.id, existingKey.id));

      log.info("[org-api-keys] deleted", {
        clerkOrgId: ctx.auth.orgId,
        keyId: input.keyId,
      });

      return { success: true };
    }),

  /**
   * Rotate an API key (revoke old, create new with same name)
   * Returns the new full key ONLY on rotation (never again)
   */
  rotate: orgScopedProcedure
    .input(rotateOrgApiKeySchema)
    .mutation(async ({ ctx, input }) => {
      const [existingKey] = await db
        .select({
          id: orgApiKeys.id,
          name: orgApiKeys.name,
          isActive: orgApiKeys.isActive,
        })
        .from(orgApiKeys)
        .where(
          and(
            eq(orgApiKeys.publicId, input.keyId),
            eq(orgApiKeys.clerkOrgId, ctx.auth.orgId)
          )
        )
        .limit(1);

      if (!existingKey) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "API key not found",
        });
      }

      const { key, prefix, suffix } = generateOrgApiKey();
      const keyHash = hashApiKey(key);

      // Batch: revoke old, create new (atomic — neon-http doesn't support transactions)
      const [, insertResult] = await db.batch([
        // Revoke old key
        db
          .update(orgApiKeys)
          .set({ isActive: false, updatedAt: new Date().toISOString() })
          .where(eq(orgApiKeys.id, existingKey.id)),
        // Create new key
        db
          .insert(orgApiKeys)
          .values({
            clerkOrgId: ctx.auth.orgId,
            createdByUserId: ctx.auth.userId,
            name: existingKey.name,
            keyHash,
            keyPrefix: prefix,
            keySuffix: suffix,
            expiresAt: input.expiresAt?.toISOString(),
          })
          .returning({
            id: orgApiKeys.id,
            publicId: orgApiKeys.publicId,
          }),
      ] as const);

      const [newKey] = insertResult;

      if (!newKey) {
        log.error("[org-api-keys] rotate failed", {
          clerkOrgId: ctx.auth.orgId,
          oldKeyId: input.keyId,
        });
        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Failed to rotate API key",
        });
      }

      log.info("[org-api-keys] rotated", {
        clerkOrgId: ctx.auth.orgId,
        oldKeyId: input.keyId,
        newKeyId: newKey.publicId,
      });

      return {
        id: newKey.publicId,
        key, // Full key - only returned once!
        name: existingKey.name,
        keyPreview: `${prefix}...${suffix}`,
        expiresAt: input.expiresAt?.toISOString() ?? null,
        createdAt: new Date().toISOString(),
      };
    }),
} satisfies TRPCRouterRecord;

import { HydrateClient, prefetch, trpc } from "@repo/app-trpc/server";
import { Suspense } from "react";

export const dynamic = "force-dynamic";

import { ProfileDataDisplay } from "./_components/profile-data-display";
import { ProfileDataLoading } from "./_components/profile-data-loading";

/**
 * General Settings Page
 *
 * Server component with optimized SSR architecture.
 *
 * Architecture:
 * - Server component: Page wrapper and static structure
 * - Client island: ProfileDataDisplay (profile data with useSuspenseQuery)
 * - Suspense boundary: Wraps ONLY the component using useSuspenseQuery
 * - Loading state: Granular skeleton matching the profile layout
 *
 * Performance pattern:
 * - Server-side prefetch of profile data (30-90x faster)
 * - HydrateClient for server-to-client state transfer
 * - Client component uses prefetched data via useSuspenseQuery
 * - No client-side fetch on mount (prevents UNAUTHORIZED errors)
 * - refetchOnMount/refetchOnWindowFocus disabled
 */
export default function GeneralSettingsPage() {
  // CRITICAL: Prefetch BEFORE HydrateClient wrapping
  prefetch(trpc.account.get.queryOptions());

  return (
    <HydrateClient>
      <Suspense fallback={<ProfileDataLoading />}>
        <ProfileDataDisplay />
      </Suspense>
    </HydrateClient>
  );
}

